+        let record = evaluator.evaluate(input).unwrap();
+        assert_eq!(record.verdict, GateVerdict::Denied);
+        let stale_eval = record
+            .evaluations
+            .iter()
+            .find(|e| e.category == GateCategory::SemanticContract)
+            .unwrap();
+        assert!(matches!(
+            stale_eval.input_validity,
+            InputValidity::Stale { .. }
+        ));
+    }
