+    #[test]
+    fn gate_history_multiple_records_verify() {
+        let mut evaluator = CutLineEvaluator::with_defaults();
+        let now = 1_000_000_000;
+
+        // Denied C0.
+        evaluator.evaluate(GateEvaluationInput {
